INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '15f1aa57-103f-4797-be0e-bdababda30b6', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_001', 'Immediately put in place a cyber-security policy that elucidates the strategy for combating cyber threats, ensuring it is duly approved by the Board.', 'Board', 'immediately', 'Need for a Board approved Cyber-security Policy', 1, 'Banks  should immediately put  in  place  a  cyber-security  policy  elucidating  the strategy containing an appropriate approach to combat cyber threats given the level of  complexity  of  business  and  acceptable  levels  of  risk,  duly  approved  by  their', '{"x0": 72.0, "y0": 153.18, "x1": 523.01, "y1": 110.67}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '5366ac0f-c031-48cd-b3a9-57e335438802', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_002', 'Establish and maintain a robust cyber security/resilience framework, ensuring adequate cybersecurity preparedness on a continuous basis.', 'Risk', 'continuous basis', 'General guidance section', 1, 'Since then, the use of technology by banks has gained further momentum. On the other  hand,  the  number,  frequency  and  impact  of  cyber  incidents  /  attacks  have increased  manifold  in  the  recent  past,  more  so  in  the  case  of  financial  sector including  banks,  underlining  the  urgent  need  to  put  in  place  a  robust  cyber security/resilience  framework  at  banks  and  to  ensure  adequate  cyber-security preparedness  among  banks  on  a  continuous  basis.  In  view  of  the  low  barriers  to entry,  evolving  nature,  growing  scale/velocity,  motivation  and  resourcefulness  of cyber-threats to the banking system, it is essential to enhance the resilience of the banking system by improving the current defences in addressing cyber risks. These would  include,  but  not  limited  to,  putting  in  place  an  adaptive  Incident  Response, Management and Recovery framework to deal with adverse incidents/disruptions, if and when they occur.', '{"x0": 72.0, "y0": 375.5, "x1": 523.12, "y1": 190.11}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
