        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'cd9822cd-dc38-435c-b4f8-57ab7f81cf26', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_004', 'Proactively create, fine-tune, or modify policies, procedures, and technologies based on new developments and emerging concerns.', 'Operations', 'None', 'Introduction section', 1, 'Use of  Information  Technology  by  banks  and  their  constituents  has  grown  rapidly and is now an integral part of the operational strategies of banks. The Reserve Bank, had,  provided  guidelines  on  Information  Security,  Electronic  Banking,  Technology Risk  Management  and  Cyber  Frauds  (G.Gopalakrishna  Committee)  vide  Circular DBS.CO.ITC.BC.No.6/31.02.008/2010-11  dated  April  29,  2011,  wherein  it  was indicated  that  the  measures  suggested  for  implementation  cannot  be  static  and banks  need  to  pro-actively  create/fine-tune/modify  their  policies,  procedures  and technologies based on new developments and emerging concerns.', '{"x0": 72.0, "y0": 510.44, "x1": 526.4, "y1": 388.55}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '4a9481c5-c36f-425e-b2f1-18025a9d447d', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_005', 'put in place a cyber-security policy elucidating the strategy containing an appropriate approach to combat cyber threats', 'Board', 'None', 'd when they occur.', 2, 'In  order  to  address  the  need  for  the  entire  bank  to  contribute  to  a  cyber-safe environment,  the  Cyber  Security  Policy  should  be  distinct  and  separate  from  the broader  IT  policy  /  IS  Security  policy  so  that  it  can  highlight  the  risks  from  cyber threats and the measures to address / mitigate these risks.', '{"x0": 72.0, "y0": 573.74, "x1": 526.4, "y1": 515.39}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '173a57f7-6a13-43ae-8211-5499767742a8', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_006', 'identify inherent risks and controls to adopt appropriate cyber-security framework', 'Risk', 'None', '', 2, 'The  size,  systems,  technological  complexity,  digital  products,  stakeholders  and threat  perception  vary  from  bank  to  bank  and  hence  it  is  important  to  identify  the inherent risks and  the controls in place to adopt appropriate cyber-security framework. While identifying and assessing the inherent risks, banks are required to reckon the technologies adopted, alignment with business and regulatory requirements, connections established, delivery channels, online / mobile products, technology services, organisational culture and internal & external threats. Depending  on  the  level  of  inherent  risks,  the  banks  are  required  to  identify  their riskiness as low, moderate,  high  and  very high or adopt  any  other similar categorisation. Riskiness of the business component also may be factored into while assessing the inherent risks. While evaluating the controls, Board oversight, policies, processes, cyber risk management architecture including experienced and qualified resources, training and culture, threat intelligence gathering arrangements, monitoring  and  analysing  the  threat  intelligence  received  vis-Ã -vis  the  situation obtaining  in  banks,  information  sharing  arrangements  (among  peer  banks,  with IDRBT/RBI/CERT-In),  preventive,  detective  and  corrective  cyber  security  controls, vendor management and incident management & response are to be outlined.', '{"x0": 72.0, "y0": 502.28, "x1": 526.4, "y1": 237.57}', 'HIGH', 'draft'
        );
