INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '79320a0e-fa49-411e-a5e7-e4684dfb564b', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_010', 'arrange for continuous surveillance Testing for vulnerabilities at reasonable intervals of time', 'Operations', 'None', '', 2, 'Arrangement for continuous surveillance', '{"x0": 72.0, "y0": 224.4, "x1": 313.44, "y1": 213.63}', 'MEDIUM', 'draft'
