INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '07a1fc5b-ae18-41d5-aa40-bcf701d57d54', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_011', 'set up a SOC (Security Operations Centre) if not yet been done', 'IT', 'at the earliest', '', 2, 'Testing  for  vulnerabilities  at  reasonable  intervals  of  time  is  very  important.  The nature of cyber-attacks are such that they can occur at any time and in a manner that  may  not  have  been  anticipated.  Hence,  it  is  mandated  that  a  SOC  (Security Operations Centre) be set up at the earliest, if not yet been done. It is also essential that this Centre ensures continuous surveillance and keeps itself regularly updated on the latest nature of emerging cyber threats.', '{"x0": 72.0, "y0": 200.64, "x1": 526.4, "y1": 110.49}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'c5abac6e-d842-4854-8a48-a15f569701ee', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_012', 'set up a SOC (Security Operations Centre) at the earliest, if not yet been done', 'Operations', 'at the earliest', '', 3, 'An indicative, but not exhaustive, minimum baseline cyber security and resilience framework  to  be  implemented  by  the  banks  is  given  in  Annex  1.  Banks  should proactively  initiate  the  process  of  setting  up  of  and  operationalising  a  Security Operations  Centre  (SOC)  to  monitor  and  manage  cyber  risks  in  real  time.  An indicative configuration of the SOC is given in Annex 2.', '{"x0": 72.0, "y0": 597.62, "x1": 526.4, "y1": 523.37}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'f1ae074c-6b80-4fc1-9e39-3f3662fe3842', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_013', 'ensure continuous surveillance and keeps itself regularly updated on the latest nature of emerging cyber threats (for SOC)', 'Operations', 'None', '', 3, 'An indicative, but not exhaustive, minimum baseline cyber security and resilience framework  to  be  implemented  by  the  banks  is  given  in  Annex  1.  Banks  should proactively  initiate  the  process  of  setting  up  of  and  operationalising  a  Security Operations  Centre  (SOC)  to  monitor  and  manage  cyber  risks  in  real  time.  An indicative configuration of the SOC is given in Annex 2.', '{"x0": 72.0, "y0": 597.62, "x1": 526.4, "y1": 523.37}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'e69a2cf7-78f6-4fab-ad8d-6de3598827e3', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_014', 'design IT architecture in such a manner that it takes care of facilitating the security measures to be in place at all times', 'IT', 'None', '', 3, 'The  IT  architecture  should  be  designed  in  such  a  manner  that  it  takes  care  of facilitating the security measures to be in place at all times. The same needs to be reviewed by the IT Sub Committee of the Board and upgraded, if required, as per their  risk  assessment  in  a  phased  manner.  The  risk  cost/potential  cost  trade  off decisions  which  a  bank  may  take  should  be  recorded  in  writing  to  enable  an appropriate supervisory assessment subsequently.', '{"x0": 72.0, "y0": 700.84, "x1": 526.4, "y1": 610.73}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '519cd1c5-973e-4ab6-8525-5cb7b8598c6f', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_015', 'review and upgrade the IT architecture, if required, as per their risk assessment in a phased manner (by IT Sub Committee of the Board)', 'Board', 'None', '', 3, 'The  IT  architecture  should  be  designed  in  such  a  manner  that  it  takes  care  of facilitating the security measures to be in place at all times. The same needs to be reviewed by the IT Sub Committee of the Board and upgraded, if required, as per their  risk  assessment  in  a  phased  manner.  The  risk  cost/potential  cost  trade  off decisions  which  a  bank  may  take  should  be  recorded  in  writing  to  enable  an appropriate supervisory assessment subsequently.', '{"x0": 72.0, "y0": 700.84, "x1": 526.4, "y1": 610.73}', 'MEDIUM', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '8265a625-022b-437f-a18a-04b81fdb3ee2', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_016', 'record the risk cost/potential cost trade off decisions in writing to enable an appropriate supervisory assessment subsequently', 'Risk', 'None', '', 3, 'The  IT  architecture  should  be  designed  in  such  a  manner  that  it  takes  care  of facilitating the security measures to be in place at all times. The same needs to be reviewed by the IT Sub Committee of the Board and upgraded, if required, as per their  risk  assessment  in  a  phased  manner.  The  risk  cost/potential  cost  trade  off decisions  which  a  bank  may  take  should  be  recorded  in  writing  to  enable  an appropriate supervisory assessment subsequently.', '{"x0": 72.0, "y0": 700.84, "x1": 526.4, "y1": 610.73}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '6c48d3a8-deee-4202-964e-67524100d7a3', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_017', 'proactively initiate the process of setting up of and operationalising a Security Operations Centre (SOC) to monitor and manage cyber risks in real time', 'Operations', 'None', '', 3, 'An indicative, but not exhaustive, minimum baseline cyber security and resilience framework  to  be  implemented  by  the  banks  is  given  in  Annex  1.  Banks  should proactively  initiate  the  process  of  setting  up  of  and  operationalising  a  Security Operations  Centre  (SOC)  to  monitor  and  manage  cyber  risks  in  real  time.  An indicative configuration of the SOC is given in Annex 2.', '{"x0": 72.0, "y0": 597.62, "x1": 526.4, "y1": 523.37}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'bc789b82-596a-42d9-bab4-350fe43a397d', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_018', 'thoroughly review network security in every bank', 'IT', 'None', '', 3, 'Recent incidents have highlighted the need to thoroughly review network security in  every  bank.  In  addition,  it  has  been  observed  that  many  times  connections  to networks/databases  are  allowed  for  a  specified  period  of  time  to  facilitate  some business or operational requirement. However, the same do not get closed due to oversight  making  the  network/database  vulnerable  to  cyber-attacks.  It  is  essential that  unauthorized  access to networks and databases is not allowed and wherever permitted,  these  are  through  well-defined  processes  which  are  invariably  followed. Responsibility over such networks and databases should be clearly elucidated and should invariably rest with the officials of the bank.', '{"x0": 72.0, "y0": 486.38, "x1": 526.4, "y1": 348.71}', 'MEDIUM', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '8a4464b9-528d-410d-b4e4-033fdfaa4958', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_019', 'ensure that unauthorized access to networks and databases is not allowed and wherever permitted, these are through well-defined processes which are invariably followed', 'Operations', 'None', '', 3, 'Recent incidents have highlighted the need to thoroughly review network security in  every  bank.  In  addition,  it  has  been  observed  that  many  times  connections  to networks/databases  are  allowed  for  a  specified  period  of  time  to  facilitate  some business or operational requirement. However, the same do not get closed due to oversight  making  the  network/database  vulnerable  to  cyber-attacks.  It  is  essential that  unauthorized  access to networks and databases is not allowed and wherever permitted,  these  are  through  well-defined  processes  which  are  invariably  followed. Responsibility over such networks and databases should be clearly elucidated and should invariably rest with the officials of the bank.', '{"x0": 72.0, "y0": 486.38, "x1": 526.4, "y1": 348.71}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '87a8f8dc-db72-47b5-b5e9-3147c608b41a', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_020', 'clearly elucidate responsibility over such networks and databases and ensure it rests with the officials of the bank', 'Operations', 'None', '', 3, 'Recent incidents have highlighted the need to thoroughly review network security in  every  bank.  In  addition,  it  has  been  observed  that  many  times  connections  to networks/databases  are  allowed  for  a  specified  period  of  time  to  facilitate  some business or operational requirement. However, the same do not get closed due to oversight  making  the  network/database  vulnerable  to  cyber-attacks.  It  is  essential that  unauthorized  access to networks and databases is not allowed and wherever permitted,  these  are  through  well-defined  processes  which  are  invariably  followed. Responsibility over such networks and databases should be clearly elucidated and should invariably rest with the officials of the bank.', '{"x0": 72.0, "y0": 486.38, "x1": 526.4, "y1": 348.71}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'b5f211bf-4ca2-49e3-a802-7e2431bf5dc8', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_021', 'take appropriate steps in preserving the Confidentiality, Integrity and Availability of customer data (irrespective of storage location)', 'Legal', 'None', '', 3, 'Banks depend on technology very heavily not only in their smooth functioning but also in providing cutting-edge digital products to their consumers and in the process collect various personal and sensitive information. Banks, as owners of such data, should take appropriate steps in preserving the Confidentiality, Integrity  and Availability of the same, irrespective of  whether the data is stored/in transit within themselves or with customers or with the third party vendors; the confidentiality of such custodial information should not be compromised at any situation and to this end, suitable systems and processes across the data/information lifecycle need to be put in place by banks.', '{"x0": 72.0, "y0": 311.7, "x1": 526.4, "y1": 173.97}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '0314f682-3db2-4163-bf0f-1efb032c655f', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_022', 'put suitable systems and processes across the data/information lifecycle to ensure confidentiality of custodial information', 'IT', 'None', '', 3, 'Banks depend on technology very heavily not only in their smooth functioning but also in providing cutting-edge digital products to their consumers and in the process collect various personal and sensitive information. Banks, as owners of such data, should take appropriate steps in preserving the Confidentiality, Integrity  and Availability of the same, irrespective of  whether the data is stored/in transit within themselves or with customers or with the third party vendors; the confidentiality of such custodial information should not be compromised at any situation and to this end, suitable systems and processes across the data/information lifecycle need to be put in place by banks.', '{"x0": 72.0, "y0": 311.7, "x1": 526.4, "y1": 173.97}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '2428ba48-65ae-4898-a4ad-1363ade4dcfa', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_023', 'put in place suitable systems and processes across the data/information lifecycle to ensure confidentiality of custodial information', 'Operations', 'None', 'null', 4, 'Sharing of information on cyber-security incidents with RBI', '{"x0": 72.0, "y0": 176.82, "x1": 414.74, "y1": 166.05}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '577bc38d-dbda-427c-a2ec-2985a7ddb7fb', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_024', 'immediately evolve a Cyber Crisis Management Plan (CCMP) and ensure it is part of the overall Board approved strategy', 'Board', 'immediately', 'null', 4, 'Cyber Crisis Management Plan', '{"x0": 72.0, "y0": 724.66, "x1": 251.4, "y1": 713.89}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'e561fb16-5c19-4b22-aa54-c2fda627185d', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_025', 'revisit traditional BCP/DR arrangements keeping in view the nuances of cyber-risk', 'Risk', 'None', 'null', 4, 'A Cyber Crisis Management Plan (CCMP) should be immediately evolved and should be a part of the overall Board approved strategy. Considering the fact that cyber-risk  is  different  from  many  other  risks,  the  traditional  BCP/DR  arrangements may not be adequate and hence needs to be revisited keeping in view the nuances of the cyber-risk.  As you may be aware, in India, CERT-IN (Computer Emergency Response Team - India, a Government entity) has been taking important initiatives in strengthening cyber-security by providing proactive & reactive services as well as guidelines, threat intelligence and assessment of preparedness of various agencies across the sectors, including the financial sector. CERT-IN also have come out with National Cyber Crisis Management Plan and Cyber Security Assessment Framework. CERT-In/NCIIPC/RBI/IDRBT guidance may be referred to while formulating the CCMP.', '{"x0": 72.0, "y0": 700.84, "x1": 526.4, "y1": 515.51}', 'MEDIUM', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '1deb1e30-1183-4334-9ec0-653aa94f8086', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_026', 'take effective measures to prevent cyber-attacks and promptly detect any cyber-intrusions so as to respond / recover / contain the fall out', 'Operations', 'None', 'null', 4, 'CCMP should address the following four aspects: (i) Detection (ii) Response (iii) Recovery and (iv) Containment.  Banks need to take effective measures to prevent cyber-attacks and to promptly detect any cyber-intrusions so as to respond / recover /  contain  the  fall  out.  Banks  are  expected  to  be  well  prepared  to  face  emerging cyber-threats  such  as  ''zero-day''  attacks,  remote  access  threats,  and  targeted attacks. Among other things, banks should take necessary preventive and corrective measures in addressing various types of cyber threats including, but not limited to, denial of service, distributed denial of services (DDoS), ransom-ware / crypto ware, destructive  malware,  business  email  frauds  including  spam,  email  phishing,  spear phishing, whaling, vishing frauds, drive-by downloads, browser gateway fraud, ghost administrator  exploits,  identity  frauds,  memory  update  frauds,  password  related frauds, etc.', '{"x0": 72.0, "y0": 502.4, "x1": 526.4, "y1": 317.09}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '116df6dc-7c86-477c-b45a-9971c0f8afe4', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_027', 'take necessary preventive and corrective measures in addressing various types of cyber threats (including but not limited to denial of service, DDoS, ransomware/crypto ware, etc.)', 'Operations', 'None', 'null', 4, 'CCMP should address the following four aspects: (i) Detection (ii) Response (iii) Recovery and (iv) Containment.  Banks need to take effective measures to prevent cyber-attacks and to promptly detect any cyber-intrusions so as to respond / recover /  contain  the  fall  out.  Banks  are  expected  to  be  well  prepared  to  face  emerging cyber-threats  such  as  ''zero-day''  attacks,  remote  access  threats,  and  targeted attacks. Among other things, banks should take necessary preventive and corrective measures in addressing various types of cyber threats including, but not limited to, denial of service, distributed denial of services (DDoS), ransom-ware / crypto ware, destructive  malware,  business  email  frauds  including  spam,  email  phishing,  spear phishing, whaling, vishing frauds, drive-by downloads, browser gateway fraud, ghost administrator  exploits,  identity  frauds,  memory  update  frauds,  password  related frauds, etc.', '{"x0": 72.0, "y0": 502.4, "x1": 526.4, "y1": 317.09}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '917526c0-e230-445d-b8ad-48fe43af47cb', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_028', 'assess and measure the adequacy of and adherence to cyber resilience framework through development of indicators', 'Risk', 'None', 'null', 4, 'The  adequacy  of  and  adherence  to  cyber  resilience  framework  should  be assessed and measured through development of indicators to assess the level of risk/preparedness.  These  indicators  should  be  used  for  comprehensive  testing through  independent  compliance  checks  and  audits  carried  out  by  qualified  and competent professionals. The awareness among the stakeholders including employees may also form a part of this assessment.', '{"x0": 72.0, "y0": 280.08, "x1": 526.4, "y1": 189.99}', 'MEDIUM', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '1b0c8d9a-b472-4f98-911b-809b8912cddd', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_029', 'use developed indicators for comprehensive testing through independent compliance checks and audits carried out by qualified and competent professionals', 'Operations', 'None', 'null', 4, 'The  adequacy  of  and  adherence  to  cyber  resilience  framework  should  be assessed and measured through development of indicators to assess the level of risk/preparedness.  These  indicators  should  be  used  for  comprehensive  testing through  independent  compliance  checks  and  audits  carried  out  by  qualified  and competent professionals. The awareness among the stakeholders including employees may also form a part of this assessment.', '{"x0": 72.0, "y0": 280.08, "x1": 526.4, "y1": 189.99}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '38c94e58-f732-488a-8608-97125f25f357', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_030', 'report all unusual cybersecurity incidents (whether they were successful or were attempts which did not fructify) to the Reserve Bank', 'Risk', 'None', 'paragraph reference or clause reference or null', 5, 'in containing cyber-risks. It is reiterated that banks need to report all unusual cybersecurity  incidents  (whether  they  were  successful  or  were  attempts  which  did  not fructify)  to  the  Reserve  Bank.  Banks are also encouraged to actively participate in the activities of their CISOs'' Forum coordinated by IDRBT and promptly report the incidents to Indian Banks - Center for Analysis of Risks and Threats (IB-CART) set up  by  IDRBT.  Such  collaborative  efforts  will  help  the  banks  in  obtaining  collective threat intelligence, timely alerts and adopting proactive cyber security measures.', '{"x0": 72.0, "y0": 724.72, "x1": 526.4, "y1": 618.71}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '2af3bb78-fd07-4250-8558-215308bba95d', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_031', 'actively participate in the activities of their CISOs'' Forum coordinated by IDRBT and promptly report the incidents to Indian Banks - Center for Analysis of Risks and Threats (IB-CART) set up by IDRBT', 'Risk', 'None', 'paragraph reference or clause reference or null', 5, 'in containing cyber-risks. It is reiterated that banks need to report all unusual cybersecurity  incidents  (whether  they  were  successful  or  were  attempts  which  did  not fructify)  to  the  Reserve  Bank.  Banks are also encouraged to actively participate in the activities of their CISOs'' Forum coordinated by IDRBT and promptly report the incidents to Indian Banks - Center for Analysis of Risks and Threats (IB-CART) set up  by  IDRBT.  Such  collaborative  efforts  will  help  the  banks  in  obtaining  collective threat intelligence, timely alerts and adopting proactive cyber security measures.', '{"x0": 72.0, "y0": 724.72, "x1": 526.4, "y1": 618.71}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '1c67cb60-f115-4136-8a9c-97738c975703', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_032', 'report promptly the incidents, in the format given in Annex-3', 'Operations', 'None', 'Supervisory Reporting framework', 5, 'It has been decided to collect both summary level information as well as details on  information  security  incidents  including  cyber-incidents.  Banks  are  required  to report promptly the incidents, in the format given in Annex-3.', '{"x0": 72.0, "y0": 581.78, "x1": 526.4, "y1": 539.27}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'f3d1c446-a14a-41a2-ae01-924a9a2c2bf3', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_033', 'An immediate assessment of gaps in preparedness to be reported to RBI', 'Risk', 'None', 'Supervisory Reporting framework', 5, 'An immediate assessment of gaps in preparedness to be reported to RBI', '{"x0": 72.0, "y0": 526.1, "x1": 490.76, "y1": 515.33}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'f3a16c84-a8c8-4bd0-be99-70f86d34977e', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_034', 'review the organisational arrangements so that the security concerns are appreciated, receive adequate attention and get escalated to appropriate levels in the hierarchy to enable quick action', 'Operations', 'None', 'Organisational arrangements', 5, 'Banks  should  review  the  organisational  arrangements  so  that  the  security concerns are appreciated, receive adequate attention and get escalated to appropriate levels in the hierarchy to enable quick action.', '{"x0": 72.0, "y0": 311.7, "x1": 526.4, "y1": 269.19}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '67e28c6e-c166-4a74-a5cd-0a421fea3c7b', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_035', 'Top Management and Board should also have a fair degree of awareness of the fine nuances of the threats and appropriate familiarisation may be organized', 'Board', 'None', 'Cyber-security awareness among stakeholders / Top Management / Board', 5, 'It  should  be  realized  that  managing  cyber  risk  requires  the  commitment  of  the entire organization to create a cyber-safe environment. This will require a high level of  awareness  among  staff  at  all  levels.  Top  Management  and  Board  should  also have a fair degree of awareness of the fine nuances of the threats and appropriate familiarisation  may  be  organized.  Banks  should  proactively  promote,  among  their customers, vendors, service providers and other relevant stakeholders an understanding  of  the  bank''s  cyber  resilience  objectives,  and  require  and  ensure appropriate action to support their synchronised implementation and testing. It is well', '{"x0": 72.0, "y0": 232.2, "x1": 526.4, "y1": 110.37}', 'MEDIUM', 'draft'
        );
