        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'c695fbcb-212b-4d4c-a879-efba5d692dac', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_037', 'Proactively promote and ensure appropriate action to support synchronized implementation and testing of cyber resilience objectives among customers, vendors, service providers, and other relevant stakeholders.', 'Operations', 'None', '', 6, 'recognised that stakeholders'' (including customers, employees, partners and vendors)  awareness  about  the  potential  impact  of  cyber-attacks  helps  in  cybersecurity preparedness of banks. Banks are required to take suitable steps in building this awareness. Concurrently, there is an urgent need to bring the Board of Directors and Top Management in banks up to speed on cyber-security related aspects, where necessary, and hence banks are advised to take immediate steps in this direction.', '{"x0": 72.0, "y0": 724.72, "x1": 526.4, "y1": 634.61}', 'HIGH', 'draft'
        );
