INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '5ce12304-fb76-4cfe-a6d7-210bd3e5fc17', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_049', 'Maintain an up-to-date inventory of Assets, including business data/information (including customer data/information), business applications, supporting IT infrastructure and facilities (hardware/software/network devices), key personnel, services, etc., indicating their business criticality.', 'IT', 'None', '1.1', 7, '1.1 Maintain an up-to-date inventory of Assets, including business data/information including customer data/information, business applications, supporting IT infrastructure  and  facilities  -  hardware/software/network  devices,  key  personnel, services,  etc.  indicating  their  business  criticality.  The  banks  may  have  their  own framework/criteria for identifying critical assets.', '{"x0": 108.02, "y0": 287.3, "x1": 526.49, "y1": 219.32}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'fc2cef09-a53c-4518-b02d-ec208ab9573e', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_050', 'Classify data/information based on information classification/sensitivity criteria of the bank.', 'Risk', 'None', '1.2', 7, '1.2 Classify data/information based on information classification/sensitivity criteria of the bank', '{"x0": 108.02, "y0": 206.54, "x1": 526.45, "y1": 182.24}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '14e71d0e-7597-4646-a8d6-12c308cf8bd4', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_051', 'Appropriately manage and provide protection within and outside organisation borders/network taking into consideration how the data/information are stored, transmitted, processed, accessed and put to use within/outside the bank''s network, and level of risk they are exposed to depending on the sensitivity of the data/information.', 'Risk', 'None', '1.3', 7, '1.3  Appropriately  manage  and  provide  protection  within  and  outside  organisation borders/network  taking  into  consideration  how  the  data/information    are  stored, transmitted, processed,  accessed and put to use within/outside the bank''s network, and  level of risk they are exposed  to depending  on  the sensitivity of the data/information.', '{"x0": 108.02, "y0": 169.46, "x1": 526.49, "y1": 101.46}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'f2f9c1db-be15-4142-a73f-a69bb9842c49', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_052', 'Appropriately manage and provide protection within and outside organisation borders/network taking into consideration how the data/information are stored, transmitted, processed, accessed and put to use within/outside the bank''s network, and level of risk they are exposed to depending on the sensitivity of the data/information.', 'Operations', 'None', 'Annex to Circular on Cyber Security Framework in Banks 1)', 8, '4.2 Maintain an up-to-date/centralised inventory of authorised devices connected to bank''s network (within/outside bank''s premises) and authorised devices enabling the bank''s network. The bank may consider implementing solutions to automate network discovery and management.', '{"x0": 108.02, "y0": 150.5, "x1": 526.49, "y1": 97.14}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '3ecea584-a530-4509-aa3b-a79f3700253d', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_053', 'Maintain an up-to-date and preferably centralised inventory of authorised/unauthorised software(s). Consider implementing whitelisting of authorised applications / software/libraries, etc.', 'IT', 'None', '2.1', 8, '2.1 Maintain an up-to-date and preferably centralised inventory of authorised/unauthorised software(s). Consider implementing whitelisting of authorised applications / software/libraries, etc.', '{"x0": 108.02, "y0": 676.18, "x1": 526.48, "y1": 637.36}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '0aae8f01-8728-4a52-8f5f-622268ce6636', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_054', 'Have mechanism to centrally/otherwise control installation of software/applications on end-user PCs, laptops, workstations, servers, mobile devices, etc. and mechanism to block /prevent and identify installation and running of unauthorised software/applications on such devices/systems.', 'IT', 'None', '2.2', 8, '2.2 Have mechanism to centrally/otherwise control installation of software/applications on end-user PCs,  laptops, workstations, servers, mobile devices, etc. and mechanism to block /prevent and identify installation and running of unauthorised software/applications on such devices/systems.', '{"x0": 108.02, "y0": 624.58, "x1": 526.51, "y1": 571.09}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '29cbaee0-65da-4dc7-badb-0b963b6aebd2', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_055', 'Continuously monitor the release of patches by various vendors / OEMs, advisories issued by CERT-in and other similar agencies and expeditiously apply the security patches as per the patch management policy of the bank.', 'IT', 'None', '2.3', 8, '2.3  Continuously  monitor  the  release  of  patches  by  various  vendors  /  OEMs, advisories issued by CERT-in and other similar agencies and expeditiously apply the security patches as per the patch management policy of the bank. If a patch/series of patches is/are released by the OEM/manufacturer/vendor for protection against wellknown/well publicised/reported attacks exploiting the vulnerability patched, the banks must have a mechanism to apply them expeditiously following an emergency patch management process.', '{"x0": 108.02, "y0": 558.31, "x1": 526.46, "y1": 461.29}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '77823154-1028-454f-8cd7-6eb8f787c2c2', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_056', 'If a patch/series of patches is/are released by the OEM/manufacturer/vendor for protection against wellknown/well publicised/reported attacks exploiting the vulnerability patched, the banks must have a mechanism to apply them expeditiously following an emergency patch management process.', 'IT', 'None', '2.3', 8, '2.3  Continuously  monitor  the  release  of  patches  by  various  vendors  /  OEMs, advisories issued by CERT-in and other similar agencies and expeditiously apply the security patches as per the patch management policy of the bank. If a patch/series of patches is/are released by the OEM/manufacturer/vendor for protection against wellknown/well publicised/reported attacks exploiting the vulnerability patched, the banks must have a mechanism to apply them expeditiously following an emergency patch management process.', '{"x0": 108.02, "y0": 558.31, "x1": 526.46, "y1": 461.29}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '4588827f-0f17-45c2-8ad1-b020506eca4e', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_057', 'Have a clearly defined framework including requirements justifying the exception(s), duration of exception(s), process of granting exceptions, and authority for approving, authority for review of exceptions granted on a periodic basis by officer(s) preferably at senior levels who are well equipped to understand the business and technical context of the exception(s).', 'IT', 'None', '2.4', 8, '2.4 Have a clearly defined framework including requirements justifying the exception(s), duration of exception(s), process of granting exceptions, and authority for  approving,  authority  for  review  of  exceptions  granted  on  a  periodic  basis  by officer(s)  preferably  at  senior  levels  who  are  well  equipped  to  understand  the business and technical context of the exception(s).', '{"x0": 108.02, "y0": 448.49, "x1": 526.49, "y1": 380.51}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'eefed592-4699-436a-b963-957ea8206d04', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_058', 'Put in place appropriate environmental controls for securing location of critical assets providing protection from natural and man-made threats.', 'Operations', 'None', '3.1', 8, '3.1  Put  in  place  appropriate  environmental  controls  for  securing  location  of  critical assets providing protection from natural and man-made threats.', '{"x0": 108.02, "y0": 343.85, "x1": 526.16, "y1": 319.55}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'b813d7ca-3f88-4de0-9b0d-7931943d4681', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_059', 'Put in place mechanisms for monitoring of breaches / compromises of environmental controls relating to temperature, water, smoke, access alarms, service availability alerts (power supply, telecommunication, servers), access logs, etc.', 'Operations', 'None', '3.2', 8, '3.2 Put in place mechanisms  for  monitoring of breaches  /  compromises  of environmental controls relating to temperature, water, smoke, access alarms, service availability  alerts  (power  supply,  telecommunication,  servers),  access  logs,  etc. Appropriate physical security measures shall be taken to protect the critical assets of the bank.', '{"x0": 108.02, "y0": 306.77, "x1": 526.49, "y1": 238.76}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
