INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '45ac364b-20bc-4400-9e5b-2256a7fb8324', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_165', 'Educate the customers on the downside risk of sharing their login credentials / passwords etc. to any third party vendor and the consequences thereof.', 'Operations', 'None', '24.3', 18, '1 - Banking Industry in India has evolved technologically over the years and currently delivering innovative services to  its  customers.  These  services  are  delivered nonstop,  round  the  clock  and  the  customers  access  these  services  using  Internet and  Mobile  Connectivity.  Security  of  the  financial  transactions  is  of  paramount importance and therefore the RBI has come out with guidelines from time to time addressing  the  security  and  operational  aspects  for  specific  applications  and services.', '{"x0": 72.02, "y0": 596.57, "x1": 526.73, "y1": 490.52}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            'eaf2459a-f95a-4582-8753-d6d2e34a6eba', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_166', 'The Cyber SoC has to take into account proactive monitoring and management capabilities with sophisticated tools for detection, quick response and backed by data and tools for sound analytics.', 'Operations', 'None', '2', 19, '2  -  The  Cyber  SoC  has  to  take  into  account  proactive  monitoring  and management capabilities with sophisticated tools for detection, quick response and backed by data and tools for sound analytics.', '{"x0": 108.02, "y0": 502.37, "x1": 526.71, "y1": 459.8}', 'HIGH', 'draft'
        );
INSERT INTO maps (id, circular_id, bank_id, map_ref, obligation_text, department_raw, deadline_raw, clause_ref, page_no, matched_text, bbox, priority, status) VALUES (
            '54c56c71-f740-4002-b620-40972ff8889b', 'd543787f-ea9a-485c-81b5-ce7765c35be5', '1ab78645-3934-4893-a4b0-354149255c6e', 'RBI/2015-16/418_MAP_167', 'The systems that NEED to be put in place as a part of the Cyber SoC requires the following aspects to be addressed: Methods to identify root cause of attacks, classify them into identified categories and come out with solutions to contain further attacks of similar types; Incident investigation, forensics and deep packet analysis need to be in place to achieve the above; Dynamic Behaviour Analysis (preliminary static & dynamic analysis and collecting Indicators of Compromise (IOC)); Analytics with good dash board, showing the Geo-location of the IP''s; Counter response and Honeypot services.', 'Operations', 'None', '4', 19, '4  -  The  systems  that  NEED to  be  put  in  place  as  a  part  of  the  Cyber  SoC requires the following aspects to be addressed.', '{"x0": 108.02, "y0": 343.59, "x1": 526.22, "y1": 316.98}', 'HIGH', 'draft'
        );
